package org.apache.commons.compress.archivers.cpio;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.apache.commons.compress.archivers.cpio.steps",
    plugin = {"pretty", "html:target/cucumber-reports"}
)
public class CucumberTest {
}

package org.apache.commons.compress.archivers.cpio.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.compress.archivers.cpio.CpioArchiveEntry;
import org.apache.commons.compress.archivers.cpio.CpioArchiveInputStream;
import org.apache.commons.compress.archivers.cpio.CpioArchiveOutputStream;
import org.apache.commons.compress.archivers.cpio.CpioConstants;
import org.junit.Assert;

import java.io.ByteArrayInputStream;
import java.io.ByteArrayOutputStream;
import java.io.IOException;

public class StepDefs {

    private ByteArrayOutputStream baos;
    private CpioArchiveOutputStream cpioOut;

    @Given("a CpioArchiveOutputStream is initialized with an output stream")
    public void initOutputStream() {
        baos = new ByteArrayOutputStream();
    }

    @Given("I create a CpioArchiveOutputStream")
    public void createCpioOut() {
        cpioOut = new CpioArchiveOutputStream(baos);
    }

    @Given("I add an entry named {string} with content")
    public void addEntry(String name) throws IOException {
        CpioArchiveEntry entry = new CpioArchiveEntry(CpioConstants.FORMAT_NEW, name, 5); 
        cpioOut.putArchiveEntry(entry);
        cpioOut.write("dummy".getBytes());
        cpioOut.closeArchiveEntry();
    }

    @When("I close the CpioArchiveOutputStream")
    public void closeCpioOut() throws IOException {
        cpioOut.close();
    }

    @Then("the underlying output stream should contain the {string} entry")
    public void checkTrailer(String trailerName) throws IOException {
        byte[] data = baos.toByteArray();
        // CPIO trailer is a file named "TRAILER!!!"
        // We can check if the byte array contains the string "TRAILER!!!"
        // In CPIO header, the name is stored.
        String content = new String(data, "US-ASCII"); 
        Assert.assertTrue("Archive should contain trailer", content.contains(trailerName));
    }

    @Then("I should be able to read the archive back using CpioArchiveInputStream without encountering an EOFException")
    public void readBack() throws IOException {
        ByteArrayInputStream bais = new ByteArrayInputStream(baos.toByteArray());
        CpioArchiveInputStream cpioIn = new CpioArchiveInputStream(bais);

        CpioArchiveEntry entry;
        try {
            while ((entry = cpioIn.getNextCPIOEntry()) != null) {
                // Consume entry
                int b;
                while ((b = cpioIn.read()) != -1) {
                    // read content
                }
            }
        } catch (java.io.EOFException e) {
             Assert.fail("Caught EOFException while reading back archive: " + e.getMessage());
        } catch (IOException e) {
            // Depending on the bug, it might throw other IOExceptions or just EOFException
             Assert.fail("Caught IOException while reading back archive: " + e.getMessage());
        }
    }
}

